import{_ as i,o as e,c as l,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"中正","description":"中与正是易经判断爻位是否妥当时最常用的两把尺子。","frontmatter":{"title":"中正","description":"中与正是易经判断爻位是否妥当时最常用的两把尺子。","category":"concept","aliases":["中正","易经中正","zhong zheng"]},"headers":[],"relativePath":"yijing/basics/concepts/zhong-zheng.md","filePath":"yijing/basics/concepts/zhong-zheng.md","lastUpdated":1777132262000}'),o={name:"yijing/basics/concepts/zhong-zheng.md"};function n(r,a,s,c,h,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="中正" tabindex="-1">中正 <a class="header-anchor" href="#中正" aria-label="Permalink to &quot;中正&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>中正其实是两个概念：</p><ul><li>中：处在适中的位置，往往对应二、五等居中之位</li><li>正：阴爻居阴位、阳爻居阳位，位置与性质相称</li></ul><p>所以“中正”不是一句抽象赞美，而是很具体的结构判断：这条爻是否既得其中，又得其正。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>把中正读成笼统的“做人要端正”</li><li>以为只要得正就一定吉</li><li>以为中正只是一条道德训诫，而不是卦爻分析工具</li></ul><p>事实上，中与正往往要分开看。有时得中而不正，有时得正而不中，判断要更细。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《易传》解释爻辞时，经常会用“得中”“得正”“中正”来说明某爻为何较稳。</li><li>九二、六二、九五、六五这些位置，常常是讨论“中”的重点。</li><li>但是否真的吉，还要结合应、承、乘、时势等关系，不可孤立判断。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可结合九二、九五、六二、六五等典型位置，补入自己的阅读体会。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/wei">位</a></li><li><a href="/Dao/yijing/basics/concepts/ying">应</a></li><li><a href="/Dao/yijing/basics/concepts/shi">时</a></li><li><a href="/Dao/yijing/basics/concepts/gang-rou">刚柔</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《彖传》</li><li>《象传》</li></ul>',16)])])}const g=i(o,[["render",n]]);export{p as __pageData,g as default};
